text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "decision": "공개 배포 목표는 스모크 테스트가 통과하면 금요일 15:00 KST로 한다.",
        "evidence": "회의 노트에 명시됨"
      },
      {
        "decision": "packageName 불일치가 발생하면 먼저 패키지 설정을 확인하고, 계약 자체가 잘못된 경우에만 스크립트를 검토한다.",
        "evidence": "회의 노트에 명시됨"
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs가 packageName 불일치를 무시하도록 바꾸는 안",
        "reason": "논의 후 거절됨"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일을 내부 stretch goal로 삼아 공개 배포를 앞당길 가능성을 남겨두는 것",
        "status": "최종 결정이 아니라 내부 목표"
      },
      {
        "goal": "README 설치 단계를 목요일까지 검토하는 것",
        "status": "가능하면 검토하자는 언급만 있었고 담당자는 미지정"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계 검토는 필요성이 언급되었지만 owner가 배정되지 않음"
      },
      {
        "item": "Hara의 tarball 경로 확인은 Minjun의 스모크 결과 이후로 미뤄졌고 정확한 기한은 정해지지 않음"
      }
    ],
    "risks": [
      {
        "risk": "tarball 경로가 잘못되면 배포가 지연될 수 있음"
      },
      {
        "risk": "README 설치 단계가 오래되면 릴리스 노트가 사용자에게 잘못된 안내를 줄 수 있음"
      }
    ],
    "open_questions": [
      {
        "question": "최종 배포 승인 권한은 누구에게 있는가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 stretch goal을 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "스모크 테스트를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "예정",
      "source_certainty": "회의 노트에 명시됨"
    },
    {
      "owner": "Doyun",
      "task": "실패 triage 메모를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "예정",
      "source_certainty": "회의 노트에 명시됨"
    },
    {
      "owner": "Hara",
      "task": "Minjun이 스모크 결과를 올린 뒤 생성된 tarball 경로를 확인한다.",
      "due": "명시되지 않음",
      "status": "후속 대기",
      "source_certainty": "회의 노트에 명시됨"
    }
  ],
  "followup_note": {
    "next_checks": [
      "금요일 10:00 KST까지 Minjun의 스모크 테스트 결과를 확인한다.",
      "금요일 12:00 KST까지 Doyun의 failure triage 메모가 action_items.md에 반영됐는지 확인한다.",
      "스모크 통과 시 공개 배포 목표를 금요일 15:00 KST로 유지할지 다시 확인한다.",
      "tarball 경로가 올바른지 확인하고, 잘못되었다면 먼저 패키지 설정을 점검한다.",
      "README 설치 단계 검토 담당자를 별도로 지정할지 확인한다.",
      "최종 배포 승인 권한자와 릴리스 노트에 내부 수요일 stretch goal을 넣을지 결정한다."
    ],
    "what_not_to_invent": [
      "고객명이나 외부 파트너명을 추정하지 않는다.",
      "예산, 보안 사고, 운영 중단, 법무 승인 요구사항을 추가하지 않는다.",
      "명시되지 않은 owner, due, approval authority를 만들어내지 않는다.",
      "공개 배포가 스모크 통과 없이 확정되었다고 쓰지 않는다.",
      "README 검토 담당자와 tarball 확인 기한을 임의로 지정하지 않는다."
    ]
  },
  "non_invention_rules": [
    "이 요약은 회의 노트에 있는 사실만 사용한다.",
    "명시되지 않은 고객, 예산, 보안, 장애, 법무, owner, deadline은 채워 넣지 않는다.",
    "수요일은 최종 공개 배포일이 아니라 내부 stretch goal로만 표기한다.",
    "Hara의 tarball 확인은 기한 미정으로 유지한다."
  ]
}
